dashboard.definition:
{
  "title": "Source - Entra ID",
  "description": "Why index Entra ID? Detect compromised accounts, track MFA compliance, prevent unauthorized access",
  "dataSources": {
    "ds_total_events": {
      "type": "ds.search",
      "name": "Total Sign-ins Over Time",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:azure:aad:signin\" | bin _time span=1h | stats count by _time"
      }
    },
    "ds_failed_logins": {
      "type": "ds.search",
      "name": "Failed Sign-in Count",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:azure:aad:signin\" properties.status.errorCode!=0 | stats count"
      }
    },
    "ds_unique_users": {
      "type": "ds.search",
      "name": "Unique User Count",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:azure:aad:signin\" | stats dc(user) as count"
      }
    },
    "ds_risky_signins": {
      "type": "ds.search",
      "name": "Risky Sign-ins",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:azure:aad:signin\" properties.status.errorCode!=0 | stats dc(user) as count"
      }
    },
    "ds_signin_timeline": {
      "type": "ds.search",
      "name": "Sign-in Success vs Failure Over Time",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:azure:aad:signin\" | eval status=if('properties.status.errorCode'=0, \"Success\", \"Failed\") | timechart span=1h count by status"
      }
    },
    "ds_failed_by_user": {
      "type": "ds.search",
      "name": "Top Failed Users",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:azure:aad:signin\" properties.status.errorCode!=0 user=* | stats count by user | sort -count | head 15"
      }
    },
    "ds_by_app": {
      "type": "ds.search",
      "name": "Sign-in by Application",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:azure:aad:signin\" | spath path=properties.appDisplayName output=appDisplayName | stats count by appDisplayName | sort -count | head 10"
      }
    },
    "ds_top_errors": {
      "type": "ds.search",
      "name": "Top Error Codes",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:azure:aad:signin\" properties.status.errorCode!=0 | stats count by properties.status.errorCode | sort -count | head 10 | rename properties.status.errorCode as \"Error Code\""
      }
    },
    "ds_sample_events": {
      "type": "ds.search",
      "name": "Recent Failed Sign-ins",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:azure:aad:signin\" properties.status.errorCode!=0 | spath path=properties.appDisplayName output=appDisplayName | spath path=properties.status.failureReason output=failureReason | table _time user appDisplayName src properties.status.errorCode failureReason | sort -_time | head 30 | rename user as \"User\" appDisplayName as \"Application\" src as \"Source IP\" properties.status.errorCode as \"Error Code\" failureReason as \"Failure Reason\""
      }
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Source — Entra ID (Azure AD)\n\n**Sourcetypes:** `FAKE:azure:aad:signin`, `FAKE:azure:aad:audit`, `FAKE:azure:aad:identity` | **Tenant:** theFakeTshirtCompany.com | **Format:** JSON\n\n**Why monitor?** Detect compromised accounts through failed sign-in patterns, identify brute-force attempts, track application access, and catch unauthorized logins before they escalate.",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_kpi_total": {
      "type": "splunk.singlevalue",
      "title": "Total Sign-ins",
      "dataSources": { "primary": "ds_total_events" },
      "options": {
        "majorValue": "> sparklineValues | lastPoint()",
        "sparklineValues": "> primary | seriesByName('count')",
        "sparklineDisplay": "below", "majorColor": "#00D2FF",
        "backgroundColor": "transparent", "showSparklineAreaGraph": true, "sparklineStrokeColor": "#00D2FF"
      }
    },
    "viz_kpi_failed": {
      "type": "splunk.singlevalue",
      "title": "Failed Sign-ins",
      "dataSources": { "primary": "ds_failed_logins" },
      "options": { "majorValue": "> primary | seriesByName('count') | lastPoint()", "majorColor": "#DC4E41", "backgroundColor": "transparent", "sparklineDisplay": "off" }
    },
    "viz_kpi_users": {
      "type": "splunk.singlevalue",
      "title": "Unique Users",
      "dataSources": { "primary": "ds_unique_users" },
      "options": { "majorValue": "> primary | seriesByName('count') | lastPoint()", "majorColor": "#7B56DB", "backgroundColor": "transparent", "sparklineDisplay": "off" }
    },
    "viz_kpi_risky": {
      "type": "splunk.singlevalue",
      "title": "Users with Failures",
      "dataSources": { "primary": "ds_risky_signins" },
      "options": { "majorValue": "> primary | seriesByName('count') | lastPoint()", "majorColor": "#F8BE34", "backgroundColor": "transparent", "sparklineDisplay": "off" }
    },
    "viz_signin_timeline": {
      "type": "splunk.area",
      "title": "Sign-in Success vs Failure Over Time",
      "dataSources": { "primary": "ds_signin_timeline" },
      "options": {
        "stackMode": "stacked", "legendDisplay": "right", "nullValueDisplay": "zero",
        "areaOpacity": 0.7, "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide", "yAxisTitleText": "Sign-ins / hour", "yAxisTitleVisibility": "show",
        "seriesColorsByField": { "Success": "#53A051", "Failed": "#DC4E41" }
      },
      "showProgressBar": true, "showLastUpdated": true
    },
    "viz_failed_by_user": {
      "type": "splunk.bar",
      "title": "Top Failed Users (Potential Compromised Accounts)",
      "dataSources": { "primary": "ds_failed_by_user" },
      "options": { "seriesColors": ["#DC4E41"], "legendDisplay": "off", "xAxisTitleText": "Failures", "xAxisTitleVisibility": "show", "yAxisTitleVisibility": "hide", "backgroundColor": "transparent" },
      "showProgressBar": true
    },
    "viz_by_app": {
      "type": "splunk.pie",
      "title": "Sign-in by Application",
      "dataSources": { "primary": "ds_by_app" },
      "options": { "labelDisplay": "valuesAndPercentage", "showDonutHole": true, "seriesColors": ["#00D2FF", "#7B56DB", "#53A051", "#F8BE34", "#DC4E41", "#009CEB", "#F1813F", "#A870EF", "#E0E0E0", "#B0B0B0"] }
    },
    "viz_top_errors": {
      "type": "splunk.bar",
      "title": "Top Error Codes",
      "dataSources": { "primary": "ds_top_errors" },
      "options": { "seriesColors": ["#F8BE34"], "legendDisplay": "off", "xAxisTitleText": "Occurrences", "xAxisTitleVisibility": "show", "yAxisTitleVisibility": "hide", "backgroundColor": "transparent" },
      "showProgressBar": true
    },
    "viz_sample_header": {
      "type": "splunk.markdown",
      "options": { "markdown": "### Recent Failed Sign-ins", "fontColor": "#C3CBD4" }
    },
    "viz_sample_events": {
      "type": "splunk.table",
      "title": "Recent Failed Sign-ins",
      "dataSources": { "primary": "ds_sample_events" },
      "options": { "count": 20, "showRowNumbers": false },
      "showProgressBar": true, "showLastUpdated": true
    }
  },
  "inputs": {
    "input_global_trp": {
      "type": "input.timerange",
      "title": "Time Range",
      "options": { "token": "global_time", "defaultValue": "1767225600,1769904000" }
    }
  },
  "defaults": {
    "dataSources": { "ds.search": { "options": { "queryParameters": { "earliest": "$global_time.earliest$", "latest": "$global_time.latest$" } } } }
  },
  "layout": {
    "type": "grid",
    "globalInputs": ["input_global_trp"],
    "structure": [
      { "item": "viz_header", "type": "block", "position": { "x": 0, "y": 0, "w": 1200, "h": 120 } },
      { "item": "viz_kpi_total", "type": "block", "position": { "x": 0, "y": 120, "w": 300, "h": 120 } },
      { "item": "viz_kpi_failed", "type": "block", "position": { "x": 300, "y": 120, "w": 300, "h": 120 } },
      { "item": "viz_kpi_users", "type": "block", "position": { "x": 600, "y": 120, "w": 300, "h": 120 } },
      { "item": "viz_kpi_risky", "type": "block", "position": { "x": 900, "y": 120, "w": 300, "h": 120 } },
      { "item": "viz_signin_timeline", "type": "block", "position": { "x": 0, "y": 240, "w": 750, "h": 350 } },
      { "item": "viz_failed_by_user", "type": "block", "position": { "x": 750, "y": 240, "w": 450, "h": 350 } },
      { "item": "viz_by_app", "type": "block", "position": { "x": 0, "y": 590, "w": 400, "h": 300 } },
      { "item": "viz_top_errors", "type": "block", "position": { "x": 400, "y": 590, "w": 800, "h": 300 } },
      { "item": "viz_sample_header", "type": "block", "position": { "x": 0, "y": 890, "w": 1200, "h": 50 } },
      { "item": "viz_sample_events", "type": "block", "position": { "x": 0, "y": 940, "w": 1200, "h": 400 } }
    ]
  }
}
